# BAD — items causes N+1 query if not prefetched
class OrderSerializer(serializers.ModelSerializer):
    items = OrderItemSerializer(many=True)  # N+1 query — one query per order

    class Meta:
        model = Order
        fields = ['id', 'items', 'total']

class OrderCreateView(APIView):
    """Create a new order for authenticated user."""

    permission_classes = [IsAuthenticated]

    def post(self, request):
        # 1. Validate input
        serializer = OrderCreateRequest(data=request.data)
        serializer.is_valid(raise_exception=True)

        # 2. Call service
        order = order_create(
            user=request.user,
            **serializer.validated_data,
        )

        # 3. Return response
        return Response(
            OrderResponse(order).data,
            status=status.HTTP_201_CREATED,
        )


class OrderListView(APIView):
    """List authenticated user's orders."""

    permission_classes = [IsAuthenticated]

    def get(self, request):
        # 1. No input validation needed for list
        orders = order_list_for_user(
            user=request.user,
            status=request.query_params.get("status"),
        )

        # 2. Paginate and serialize
        paginator = LimitOffsetPagination()
        page = paginator.paginate_queryset(orders, request)

        return paginator.get_paginated_response(
            OrderListResponse(page, many=True).data
        )
